THOUGHT: The assertion occurs when encountering a VPRecipe that is not VPRecipeWithIRFlags but has an underlying Instruction with poison-generating flags (nnan), likely VPWidenIntrinsic for fabs. A straightforward fix is to extend the check to treat VPWidenIntrinsic similarly by dropping poison flags when encountered. I will locate VPWidenIntrinsic definition sites to confirm and then patch VPlanTransforms.cpp to handle VPWidenIntrinsic in the same branch as VPRecipeWithIRFlags.

```bash
grep -Rn "VPWidenIntrinsic" llvm | head -n 20 && sed -n '1888,1932p' llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp && applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Vectorize/VPlanTransforms.cpp
@@
-      if (auto *RecWithFlags = dyn_cast<VPRecipeWithIRFlags>(CurRec)) {
+      // Some recipes like VPWidenIntrinsic may carry underlying instructions
+      // with poison-generating flags (e.g. nnan on fabs). Handle them similarly
+      // to VPRecipeWithIRFlags by dropping poison-generating flags to avoid
+      // triggering the assertion below.
+      if (auto *RecWithFlags = dyn_cast<VPRecipeWithIRFlags>(CurRec)) {
         VPValue *A, *B;
         using namespace llvm::VPlanPatternMatch;
@@
-        } else
-          RecWithFlags->dropPoisonGeneratingFlags();
+        } else
+          RecWithFlags->dropPoisonGeneratingFlags();
+      } else if (isa<VPWidenIntrinsic>(CurRec)) {
+        // If the underlying instruction has poison-generating flags, drop them.
+        if (Instruction *Instr = dyn_cast_or_null<Instruction>(
+                CurRec->getVPSingleValue()->getUnderlyingValue())) {
+          if (Instr->hasPoisonGeneratingFlags()) {
+            // Create a temporary VPInstruction wrapper to reuse flag dropping
+            // behavior via VPRecipeWithIRFlags interface if available. Otherwise,
+            // directly clear relevant flags on the underlying instruction.
+            // Since we don't have a recipe with IR flags here, clear all poison
+            // generating flags from the IR Instruction.
+            Instr->clearPoisonGeneratingFlags();
+          }
+        }
       } else {
         Instruction *Instr = dyn_cast_or_null<Instruction>(
             CurRec->getVPSingleValue()->getUnderlyingValue());
         (void)Instr;
         assert((!Instr || !Instr->hasPoisonGeneratingFlags()) &&
                "found instruction with poison generating flags not covered by "
                "VPRecipeWithIRFlags");
       }
*** End Patch
EOF
```

